global median, midpoint, searchNum, listCopy, counter


def findMid(midList):
    global median, midpoint
    if len(midList) % 2 == 0:
        midpoint = int(len(midList) / 2)
        median = midList[midpoint]
    else:
        midpoint = int((len(midList) - 1) / 2)
        median = midList[midpoint]
    # print(median)
    return midpoint, median


def listSplit(listName, n):
    global searchNum, listCopy, counter
    if len(listName) == 1:
        if listName[0] != n:
            print("Number not found.  Adding", n, "to your list.")
            listCopy.append(n)
            listCopy.sort()
            counter += 1
        else:
            print("Found!")
            counter += 1
    if len(listName) > 1:
        if n == median:
            print("Found!")
            print(searchNum)
            counter += 1
        elif n > median:
            print("Searching upper half...")
            listName = listName[midpoint:len(listName)]
            print(listName)
            findMid(listName)
            listSplit(listName, n)
            counter += 1
        elif n < median:
            print("Searching lower half...")
            listName = listName[0:midpoint]
            print(listName)
            findMid(listName)
            listSplit(listName, n)
            counter += 1


def main(listName):
    global median, searchNum, listCopy, counter
    counter = 0
    listCopy = listName
    findMid(listName)
    searchNum = int(input("Enter the number to search for: "))
    print(searchNum)
    listSplit(listName, searchNum)
    listName = listCopy
    print("This process took", counter, "cycles to find the solution")
    print(listName)


main(myList)
